#include <bits/stdc++.h>
using namespace std;

const int N=1e5+10;

struct Node{
    int h,l;
}b[N][11];

int n,k,pos[N],s[N],sc[N][2];
long long g[N][2],f[N][2],cnt[N];

bool cmp(Node x,Node y){
    return x.h<y.h;
}

int solve(long long num){
    memset(f,0xcf,sizeof(f));
    memset(sc,0x3f,sizeof(sc));
    f[0][0]=0;
    sc[0][0]=0;
    for(int i=1;i<=n;i++){
        f[i][0]=max(f[i-1][1]+g[i-1][1],f[i-1][0]);
        if(f[i][0]==f[i-1][1]+g[i-1][1])
			sc[i][0]=min(sc[i][0],sc[i-1][1]);
        if(f[i][0]==f[i-1][0])
			sc[i][0]=min(sc[i][0],sc[i-1][0]);

        f[i][1]=max(f[i-1][1],f[i-1][0]+g[i][0])+cnt[i]-num;
        if(f[i][1]==f[i-1][1]+cnt[i]-num)
			sc[i][1]=min(sc[i][1],sc[i-1][1]+1);
        if(f[i][1]==f[i-1][0]+g[i][0]+cnt[i]-num)
			sc[i][1]=min(sc[i][1],sc[i-1][0]+1);
    }
    if(f[n][0]>f[n][1])
        return sc[n][0];
    if(f[n][0]<f[n][1])
        return sc[n][1];
    return min(sc[n][0],sc[n][1]);
}

int main(){
    scanf("%d%d",&n,&k);
    for(int i=1;i<=n;i++)
        scanf("%d",&pos[i]);
    for(int i=1;i<=n;i++)
        scanf("%d",&s[i]);
    for(int i=1;i<=n;i++){
        for(int j=1;j<=s[i];j++)
            scanf("%d",&b[i][j].h);
        for(int j=1;j<=s[i];j++){
            scanf("%d",&b[i][j].l);
            cnt[i]+=abs(b[i][j].l);
        }
        sort(b[i]+1,b[i]+s[i]+1,cmp);
    }
    for(int i=1;i<n;i++){
        int mx=0;
        for(int j=1,k=1;j<=s[i];j++){
            while(k<=s[i+1] && b[i+1][k].h<b[i][j].h){
                mx=max(mx,-b[i+1][k].l);
                k++;
            }
            if(b[i][j].l>0)
                g[i+1][0]+=max(0,mx+b[i][j].l-(pos[i+1]-pos[i]-1));
        }
        mx=0;
        for(int j=1,k=1;j<=s[i+1];j++){
            while(k<=s[i] && b[i][k].h<b[i+1][j].h){
                mx=max(mx,b[i][k].l);
                k++;
            }
            if(b[i+1][j].l<0)
                g[i][1]+=max(0,mx-b[i+1][j].l-(pos[i+1]-pos[i]-1));
        }
    }
    long long l=0,r=1e10;
    while(l<r){
        long long mid=l+r>>1;
        if(solve(mid)<=k)
            r=mid;
        else
            l=mid+1;
    }
    solve(l);

//    printf("%lld",max(f[n][0]+sc[n][0]*l,f[n][1]+sc[n][1]*l));
	long long ans=-1e18;
	printf("%lld",max(f[n][0],f[n][1])+k*l);
    return 0;
}
